mapper.select:
SELECT id, user_id, view_id, report_key, period_key, query_cycle, filter_json, report_json, created_at
FROM analytics_query_snapshot
WHERE user_id = #{userId}
  AND view_id = #{viewId}
  AND report_key = #{reportKey}
  AND period_key = #{periodKey}
LIMIT 1

mapper.delete:
DELETE FROM analytics_query_snapshot
WHERE user_id = #{userId}
  AND view_id = #{viewId}
  AND report_key = #{reportKey}
  AND period_key = #{periodKey}

mapper.insert:
INSERT INTO analytics_query_snapshot (
    user_id, view_id, report_key, period_key, query_cycle, filter_json, report_json
) VALUES (
    #{userId}, #{viewId}, #{reportKey}, #{periodKey}, #{queryCycle}, #{filterJson}, #{reportJson}
)
